#### Flink Job (Order Processing)
```java
public class OrderProcessingJob extends RichParallelSourceFunction<Order> {

    @Override
    public void run(SourceContext<Order> ctx) throws Exception {
        Properties props = new Properties();
        props.setProperty("bootstrap.servers", "localhost:9092");

        KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);
        consumer.subscribe(Arrays.asList("order_placed_topic"));

        while (true) {
            ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));

            for (ConsumerRecord<String, String> record : records) {
                Order order = new ObjectMapper().readValue(record.value(), Order.class);

                // Process the order
                processOrder(order);

                ctx.collect(order);
            }
        }
    }

    private void processOrder(Order order) {
        // Decrease inventory and publish INVENTORY_DECREASED event if successful
    }
}
```

