#### 2. **Compensation Logic**

Implement the compensation logic to emit a compensating event.

```java
@Service
public class OrderService {

    @Autowired
    private KafkaTemplate<String, String> kafkaTemplate;

    public void placeOrder(Order order) {
        try (TransactionStatus status = new TransactionStatus()) {
            // Validate the order
            if (!validateOrder(order)) return;

            // Publish ORDER_PLACED event to Kafka
            kafkaTemplate.send("order_placed_topic", "ORDER_PLACED", new ObjectMapper().writeValueAsString(order));

            // Send payment request to Payment Gateway Service
            kafkaTemplate.send("payment_received_topic", "PAYMENT_REQUESTED", createPaymentRequestEvent(order));

            status.commit();
        } catch (Exception ex) {
            log.error("Failed to process ORDER_PLACED event for order: {}", order, ex);

            // Emit compensation event if necessary
            try {
                kafkaTemplate.send("order_compensation_topic", "ORDER_COMPENSATION", createOrderCompensationEvent(order));
            } catch (Exception compensateEx) {
                log.error("Failed to send ORDER_COMPENSATION event for order: {}", order, compensateEx);
            }

            throw new OrderProcessingException("Failed to process the order", ex);
        }
    }

    private String createPaymentRequestEvent(Order order) {
        // Create and serialize payment request event
        PaymentRequestedEvent paymentRequestEvent = new PaymentRequestedEvent(order.getOrder_id(), order.getTotal_amount());
        return new ObjectMapper().writeValueAsString(paymentRequestEvent);
    }

    private String createOrderCompensationEvent(Order order) {
        // Create and serialize compensation event
        OrderCompensationEvent compensationEvent = new OrderCompensationEvent("ORDER_COMPENSATION", order.getId(), "FAILED");
        return new ObjectMapper().writeValueAsString(compensationEvent);
    }
}
```

