@Service
public class InventoryManagementService {

    @Autowired
    private KafkaTemplate<String, String> kafkaTemplate;

    public void processOrderPlacedEvent(Order order) {
        try (TransactionStatus status = new TransactionStatus()) {
            // Decrease inventory in PostgreSQL
            Inventory savedInventory = inventoryRepository.decreaseInventory(order.getProduct_id(), order.getQuantity());

            // Publish INVENTORY_DECREASED event to Kafka
            kafkaTemplate.send("inventory_update_topic", "INVENTORY_DECREASED", createInventoryDecreaseEvent(savedInventory));

            status.commit();
        } catch (Exception ex) {
            log.error("Failed to process ORDER_PLACED event for product: {}", order.getProduct_id(), ex);
            throw new InventoryManagementException("Failed to update inventory", ex);
        }
    }

    public void compensateOrderPlacedEvent(Order order) {
        try (TransactionStatus status = new TransactionStatus()) {
            // Revert the inventory increase
            inventoryRepository.revertInventory(order.getProduct_id(), order.getQuantity());

            status.commit();
        } catch (Exception ex) {
            log.error("Failed to revert ORDER_PLACED event for product: {}", order.getProduct_id(), ex);
            throw new InventoryManagementException("Failed to revert inventory", ex);
        }
    }

    private String createInventoryDecreaseEvent(Inventory inventory) {
        // Create and serialize inventory decrease event
        return new ObjectMapper().writeValueAsString(new InventoryDecreasedEvent(inventory));
    }
}
