                    // Process the order (example: decrease inventory)
                    InventoryDecreasedEvent inventoryDecreaseEvent = createInventoryDecreaseEvent(orderPlacedEvent);

                    return new ObjectMapper().writeValueAsString(inventoryDecreaseEvent);
