            status.commit();
        } catch (Exception ex) {
            log.error("Failed to process ORDER_PLACED event from DLQ: {}", message, ex);

            // Retry logic
            if (!retryLogic(ex)) {
                moveToDeadLetterQueue(message);  // Move back to DLQ if still fails
            }

            throw new RuntimeException(ex);
        }
    }

    private boolean retryLogic(Exception ex) {
